import {
  CanActivate,
  ExecutionContext,
  ForbiddenException,
  Injectable,
} from '@nestjs/common';
import type { Request } from 'express';
import { PrismaService } from '../prisma/prisma.service';

/**
 * IDOR protection (README §2.5 A01). For user-owned session routes carrying an
 * `:id` param, compares the resource's `userId` against the JWT `sub`. A
 * mismatch → 403. Applied at the controller/route level so it cannot be skipped.
 * (Defense-in-depth: the service also re-checks ownership.)
 */
@Injectable()
export class ResourceOwnershipGuard implements CanActivate {
  constructor(private readonly prisma: PrismaService) {}

  async canActivate(ctx: ExecutionContext): Promise<boolean> {
    const request = ctx
      .switchToHttp()
      .getRequest<Request & { user?: { sub: string } }>();
    const userId = request.user?.sub;
    if (!userId) throw new ForbiddenException('Not authenticated.');

    const sessionId = request.params?.id;
    if (!sessionId) return true; // nothing to scope

    const session = await this.prisma.shoppingSession.findUnique({
      where: { id: sessionId },
      select: { userId: true },
    });
    // Unknown id → let the service raise a precise 404 rather than a vague 403.
    if (!session) return true;

    if (session.userId !== userId) {
      throw new ForbiddenException('You do not own this resource.');
    }
    return true;
  }
}
